public void startConfirm()
{
    RefRecId defDimension;
    AgreementLine agreementLineLoc;
    AgreementHeader headerLoc;
    SalesAgreementHeader soHeaderLoc;
    PurchAgreementHeader poHeaderLoc;

    headerLoc = this.parmAgreementHeader();
    select firstonly soHeaderLoc where soHeaderLoc.RecId == headerLoc.RecId;

    if (soHeaderLoc.ETG_PurchAgreementIdIC)
    {
        select firstonly poHeaderLoc where poHeaderLoc.purchnumbersequence == soHeaderLoc.ETG_PurchAgreementIdIC;
        //headerLoc = this.parmAgreementHeader();
        defDimension = poHeaderLoc.DefaultDimension;
    }
    next startConfirm();
    if (soHeaderLoc.ETG_PurchAgreementIdIC)
    {
        while select agreementLineLoc
            where agreementLineLoc.Agreement == poHeaderLoc.RecId
        {
            ttsbegin;
            agreementLineLoc.selectForUpdate(true);
            agreementLineLoc.DefaultDimension = defDimension;
            agreementLineLoc.doUpdate();
            ttscommit;
        }
        //update_recordset agreementLineLoc setting DefaultDimension = defDimension where agreementLineLoc.Agreement == poHeaderLoc.RecId;
        //update_recordset agreementLineLoc setting DefaultDimension = defDimension where agreementLineLoc.Agreement == soHeaderLoc.RecId;
    }


    //NS Update remaining trade limit if workflow is disabled
    if(ETGACFParameters::find().EnableTradeLimit == NoYes::Yes)
    {
        AgreementHeaderHistory       agreementHeaderHistory;

        select firstonly agreementHeaderHistory
        order by RecId desc
        where agreementHeaderHistory.AgreementHeader == soHeaderLoc.RecId;

        if(agreementHeaderHistory.ConfirmationNumber == "1"
            && soHeaderLoc.custTable().ETGApplicableTradeLimit == NoYes::Yes
            && ETGACFParameters::find().EnableSalesAgreementWorkflow == NoYes::No)
        {
            ETGACFTradeLimitHelper::processTradeLimitSales(soHeaderLoc);
        }
    }

    //NE Update remaining trade limit if workflow is disabled

    //DMF Intergreations..*/

    if (ETGACFParameters::find().EnableDMSIntegration
        && BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereSalesAgreementIntegrationEventClass)))
    {
        AgreementHeaderHistory       agreementHeaderHistory;
        select firstonly agreementHeaderHistory
                order by RecId desc
                where agreementHeaderHistory.AgreementHeader == soHeaderLoc.RecId;

        str confirmationnumber  = strFmt("%1-%2", soHeaderLoc.SalesNumberSequence, agreementHeaderHistory.ConfirmationNumber);
        str formattedDateTime = DateTimeUtil::toStr(agreementHeaderHistory.CreatedDateTime); 
        str effectiveDate = DateTimeUtil::toStr(soHeaderLoc.DefaultAgreementLineEffectiveDate);

        ETGDMSRevereSalesAgreementIntegrationContract contract = new ETGDMSRevereSalesAgreementIntegrationContract();

        contract.parmDealNumber(soHeaderLoc.ETGDMSDealNumber);
        contract.parmDataAreaId(curExt());
        contract.parmOperationType("Confirmation");
        contract.parmActivityName("Sales Agreement Confirmation");
        contract.parmDocumentNumber(confirmationnumber);
        contract.parmDocumentDate(formattedDateTime);
        contract.parmActivityOwner(soHeaderLoc.CreatedBy);
        contract.parmActivityRemarks(strFmt("The Sales agreement %1 is confirmed",soHeaderLoc.SalesNumberSequence));
        contract.parmEffectiveDate(effectiveDate);

        ETGDMSRevereSalesAgreementIntegrationEventClass eventClass = ETGDMSRevereSalesAgreementIntegrationEventClass::newFromContract(contract);
        eventClass.send();
    }


}
